    <style>
  #loading {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-color: #ffffff;
    z-index: 9999;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    transition: opacity 0.5s ease, visibility 0.5s;
}

/* Contenedor del spinner y texto */
.spinner-container {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 20px; /* Espacio entre la animaciòn y el texto */
}

/* Estilos del Logo SVG */
.spinner-logo {
    width: 120px; /* Ajusta el tamao segùn tu imagen */
    height: auto;
    animation: pulseLogo 1.5s ease-in-out infinite;
}

@keyframes pulseLogo {
    0% { transform: scale(1); opacity: 1; }
    50% { transform: scale(1.05); opacity: 0.8; }
    100% { transform: scale(1); opacity: 1; }
}

/* Mantenemos la animaciòn de los anillos (del còdigo anterior) */
.spinner-wrapper {
    position: relative;
    width: 60px;
    height: 60px;
}

.spinner-ring {
    position: absolute;
    width: 100%;
    height: 100%;
    border-radius: 50%;
    border: 4px solid transparent;
    border-top-color: #004c99;
    animation: spin 1s linear infinite;
}

.spinner-ring::before {
    content: "";
    position: absolute;
    top: 8px;
    left: 8px;
    right: 8px;
    bottom: 8px;
    border-radius: 50%;
    border: 4px solid transparent;
    border-top-color: #15e1dd;
    animation: spin 2s linear infinite reverse;
}

.spinner-ring::after {
    content: "";
    position: absolute;
    top: 24px;
    left: 24px;
    right: 24px;
    bottom: 24px;
    border-radius: 50%;
    background-color: #99b5da;
    animation: pulse 1.5s ease-in-out infinite;
}

.loading-text {
    margin-top: 10px;
    font-size: 0.5rem;
    font-weight: 400;
    color: #004c99;
    text-align: center;
    letter-spacing: 1px;
    text-transform: uppercase;
    animation: fadeIn 1.5s ease-in-out;
}

@keyframes spin {
    0% { transform: rotate(0deg); }
    100% { transform: rotate(360deg); }
}

@keyframes pulse {
    0% { transform: scale(0.5); opacity: 0.5; }
    50% { transform: scale(1); opacity: 1; }
    100% { transform: scale(0.5); opacity: 0.5; }
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(10px); }
    to { opacity: 1; transform: translateY(0); }
}
    </style>
    
